#include<bits/stdc++.h>
using namespace std;
int n,m;
int fa[1000010],siz[1000010];
struct Stack
{
    int x,y;
}s[32000010];
int top;
struct edge
{
    int x,y;
};
vector<edge> t[1600010];
int find(int x)
{
    while(x!=fa[x])
    {
        x=fa[x];
    }
    return x;
}
int cnt;
void merge(int x,int y)
{
    int a=find(x),b=find(y);
    if(a==b)
    {
        return;
    }
    if(siz[a]>siz[b])
    {
        swap(a,b);
    }
    cnt--;
    s[++top]=(Stack){a,b};
    siz[b]+=siz[a];
    fa[a]=b;
}
void update(int x,int l,int r,int L,int R,edge v)
{
    if(L>R||l>R||L>r)
    {
        return;
    }
    if(L<=l&&r<=R)
    {
        t[x].push_back(v);
        return;
    }
    int mid=(l+r)>>1;
    update(x<<1,l,mid,L,R,v);
    update(x<<1|1,mid+1,r,L,R,v);
}
void solve(int x,int l,int r)
{
    int lst=top;
    for(auto i:t[x])
    {
        merge(i.x,i.y);
    }
    if(l==r)
    {
        if(siz[find(1)]==n)
        {
            printf("%d",l-1);
            exit(0);
        }
    }
    else
    {
        int mid=(l+r)>>1;
        solve(x<<1,l,mid);
        solve(x<<1|1,mid+1,r);
    }
    while(top>lst)
    {
        int k=s[top].x;
        while(k!=fa[k])
        {
            k=fa[k];
            siz[k]-=siz[s[top].x];
        }
        cnt++;
        fa[s[top].x]=s[top].x;
        top--;
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int x,y,w;
        scanf("%d%d%d",&x,&y,&w);
        if(w!=0)
        {
            update(1,1,1e5+2,1,w,(edge){x,y});
        }
        update(1,1,1e5+2,w+2,1e5+2,(edge){x,y});
    }
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
        siz[i]=1;
    }
    cnt=n;
    solve(1,1,1e5+2);
    return 0;
}
